    it: { name: "Generatore di smart / deep link", short: "Un solo link che apre la tua app su iOS e Android, con fallback web.", h1: "Generatore di smart & deep link — Un link per iOS, Android e web", metaTitle: "Generatore di smart / deep link — App + fallback web | Konvertools", metaDescription: "Crea un unico link intelligente che apre la tua app iOS o Android se installata e reindirizza a una pagina web altrove. Controllo antiphishing. Gratis, accesso richiesto." },
    nl: { name: "Smart/deep link-generator", short: "Eén link die je app opent op iOS & Android, met web-fallback.", h1: "Smart & deep link-generator — één link voor iOS, Android & web", metaTitle: "Smart/deep link-generator — app + web-fallback | Konvertools", metaDescription: "Maak één slimme link die je iOS- of Android-app opent als die is geïnstalleerd, en anders naar een webpagina gaat. Antiphishing-gescreend. Gratis, inloggen vereist." },
    ja: { name: "スマート / ディープリンク生成", short: "iOS と Android でアプリを開き、Web にフォールバックする 1 つのリンク。", h1: "スマート & ディープリンク生成 — iOS・Android・Web を 1 つのリンクで", metaTitle: "スマート / ディープリンク生成 — アプリ + Web フォールバック | Konvertools", metaDescription: "インストール済みなら iOS / Android アプリを開き、それ以外では Web ページに切り替わるスマートリンクを 1 つ作成。フィッシング検査済み。無料、要ログイン。" },
    zh: { name: "智能 / 深度链接生成器", short: "一个链接即可在 iOS 和 Android 打开您的应用，并支持网页回退。", h1: "智能 & 深度链接生成器 — 一个链接通用于 iOS、Android 和网页", metaTitle: "智能 / 深度链接生成器 — 应用 + 网页回退 | Konvertools", metaDescription: "创建一个智能链接：已安装时打开您的 iOS 或 Android 应用，否则回退到网页。经反钓鱼检测。免费，需要登录。" },
    ko: { name: "스마트 / 딥링크 생성기", short: "iOS & Android 에서 앱을 열고 웹으로 폴백하는 단 하나의 링크.", h1: "스마트 & 딥링크 생성기 — iOS, Android, 웹을 하나의 링크로", metaTitle: "스마트 / 딥링크 생성기 — 앱 + 웹 폴백 | Konvertools", metaDescription: "설치되어 있으면 iOS 또는 Android 앱을 열고, 그 외에는 웹 페이지로 이동하는 스마트 링크 하나를 만드세요. 피싱 검사 완료. 무료, 로그인 필요." },
    ar: { name: "مولّد الروابط الذكية / العميقة", short: "رابط واحد يفتح تطبيقك على iOS وAndroid مع بديل ويب.", h1: "مولّد الروابط الذكية والعميقة — رابط واحد لـ iOS وAndroid والويب", metaTitle: "مولّد الروابط الذكية / العميقة — تطبيق + بديل ويب | Konvertools", metaDescription: "أنشئ رابطًا ذكيًا واحدًا يفتح تطبيق iOS أو Android إذا كان مثبتًا، ويتحول إلى صفحة ويب في غير ذلك. فحص ضد التصيّد. مجاني، يتطلب تسجيل الدخول." },
    ru: { name: "Генератор smart/deep-ссылок", short: "Одна ссылка открывает ваше приложение на iOS и Android с веб-резервом.", h1: "Генератор smart и deep-ссылок — одна ссылка для iOS, Android и веба", metaTitle: "Генератор smart/deep-ссылок — приложение + веб-резерв | Konvertools", metaDescription: "Создайте одну умную ссылку: она открывает приложение iOS или Android, если оно установлено, иначе ведёт на веб-страницу. Проверка на фишинг. Бесплатно, требуется вход." },
    hi: { name: "स्मार्ट / डीप लिंक जनरेटर", short: "एक ही लिंक iOS और Android पर आपका ऐप खोले, वेब फ़ॉलबैक के साथ.", h1: "स्मार्ट और डीप लिंक जनरेटर — iOS, Android और वेब के लिए एक लिंक", metaTitle: "स्मार्ट / डीप लिंक जनरेटर — ऐप + वेब फ़ॉलबैक | Konvertools", metaDescription: "एक स्मार्ट लिंक बनाएँ जो इंस्टॉल होने पर आपका iOS या Android ऐप खोले और अन्यथा वेब पेज पर ले जाए. एंटी-फ़िशिंग जाँच. मुफ़्त, साइन-इन आवश्यक." },
    tr: { name: "Akıllı / Derin Bağlantı Üretici", short: "iOS ve Android'de uygulamanızı açan, web yedekli tek bağlantı.", h1: "Akıllı & Derin Bağlantı Üretici — iOS, Android ve Web için Tek Bağlantı", metaTitle: "Akıllı / Derin Bağlantı Üretici — Uygulama + Web Yedeği | Konvertools", metaDescription: "Yüklüyse iOS veya Android uygulamanızı açan, değilse bir web sayfasına yönlenen tek bir akıllı bağlantı oluşturun. Kimlik avı taramalı. Ücretsiz, oturum açma gerekli." },
    id: { name: "Generator Smart / Deep Link", short: "Satu tautan yang membuka aplikasi Anda di iOS & Android, dengan fallback web.", h1: "Generator Smart & Deep Link — Satu Tautan untuk iOS, Android & Web", metaTitle: "Generator Smart / Deep Link — Aplikasi + Fallback Web | Konvertools", metaDescription: "Buat satu tautan pintar yang membuka aplikasi iOS atau Android saat terpasang dan beralih ke halaman web di tempat lain. Diperiksa anti-phishing. Gratis, perlu masuk." },
    vi: { name: "Trình tạo smart / deep link", short: "Một liên kết mở ứng dụng của bạn trên iOS & Android, kèm dự phòng web.", h1: "Trình tạo smart & deep link — Một liên kết cho iOS, Android & web", metaTitle: "Trình tạo smart / deep link — Ứng dụng + dự phòng web | Konvertools", metaDescription: "Tạo một liên kết thông minh duy nhất: mở ứng dụng iOS hoặc Android khi đã cài đặt, nếu không sẽ chuyển sang trang web. Đã kiểm tra chống lừa đảo. Miễn phí, cần đăng nhập." },
